PowerShell 5+ supporte les classes orientées objet :

```powershell
class Personne {
    # Propriétés
    [string]$Nom
    [string]$Prenom
    [int]$Age

    # Constructeur par défaut
    Personne() {}

    # Constructeur avec paramètres
    Personne([string]$nom, [string]$prenom, [int]$age) {
        $this.Nom    = $nom
        $this.Prenom = $prenom
        $this.Age    = $age
    }

    # Méthode
    [string] NomComplet() {
        return "$($this.Prenom) $($this.Nom)"
    }

    [bool] EstMajeur() {
        return $this.Age -ge 18
    }

    # Override ToString
    [string] ToString() {
        return "$($this.NomComplet()) ($($this.Age) ans)"
    }
}

$p = [Personne]::new("Dupont", "Alice", 30)
Write-Host $p.NomComplet()   # Alice Dupont
Write-Host $p.EstMajeur()    # True
Write-Host $p                # Alice Dupont (30 ans)
```

```powershell
class Animal {
    [string]$Nom
    [string]$Son

    Animal([string]$nom) {
        $this.Nom = $nom
    }

    [string] Parler() {
        return "$($this.Nom) fait : $($this.Son)"
    }

    [string] ToString() { return "Animal: $($this.Nom)" }
}

class Chien : Animal {
    [string]$Race

    Chien([string]$nom, [string]$race) : base($nom) {
        $this.Son  = "Wouf"
        $this.Race = $race
    }

    [string] Parler() {
        return "$($this.Nom) ($($this.Race)) : WOUF !"
    }
}

class Chat : Animal {
    Chat([string]$nom) : base($nom) {
        $this.Son = "Miaou"
    }
}

$chien = [Chien]::new("Rex", "Labrador")
$chat  = [Chat]::new("Misty")

@($chien, $chat) | ForEach-Object { Write-Host $_.Parler() }
```

```powershell
class Compteur {
    # Propriété statique (partagée par toutes les instances)
    static [int]$NbInstances = 0

    [string]$Nom
    hidden [int]$_valeur = 0   # propriété masquée

    Compteur([string]$nom) {
        $this.Nom = $nom
        [Compteur]::NbInstances++
    }

    # Getter/Setter via méthodes
    [int] GetValeur() { return $this._valeur }

    Incrementer() { $this._valeur++ }

    Reset() { $this._valeur = 0 }

    # Méthode statique
    static [void] AfficherStats() {
        Write-Host "Instances créées : $([Compteur]::NbInstances)"
    }
}

$c1 = [Compteur]::new("A")
$c2 = [Compteur]::new("B")
$c1.Incrementer(); $c1.Incrementer()

[Compteur]::AfficherStats()    # Instances créées : 2
Write-Host $c1.GetValeur()     # 2
```

```powershell
# Implémenter une interface .NET
class MaListe : System.Collections.Generic.IEnumerable[object] {
    hidden [System.Collections.Generic.List[object]]$_items = 
        [System.Collections.Generic.List[object]]::new()

    Add([object]$item) { $this._items.Add($item) }

    [System.Collections.Generic.IEnumerator[object]] GetEnumerator() {
        return $this._items.GetEnumerator()
    }

    [System.Collections.IEnumerator] 
    [System.Collections.IEnumerable]::GetEnumerator() {
        return $this._items.GetEnumerator()
    }
}

# Utiliser des types génériques .NET
$dict = [System.Collections.Generic.Dictionary[string, int]]::new()
$dict['pomme'] = 5
$dict['poire'] = 3
$dict.ContainsKey('pomme')   # True

# Stack et Queue
$stack = [System.Collections.Generic.Stack[string]]::new()
$stack.Push("premier")
$stack.Push("deuxième")
$stack.Pop()  # deuxième (LIFO)
```

```powershell
# Énumération
enum Statut {
    Inconnu  = 0
    Actif    = 1
    Inactif  = 2
    Supprime = 3
}

class Utilisateur {
    [string]$Login
    [Statut]$Statut = [Statut]::Actif
    [datetime]$Création = (Get-Date)

    Utilisateur([string]$login) {
        $this.Login = $login
    }

    Desactiver() {
        $this.Statut = [Statut]::Inactif
    }

    [bool] EstActif() {
        return $this.Statut -eq [Statut]::Actif
    }

    [string] ToString() {
        return "[$($this.Statut)] $($this.Login)"
    }
}

$u = [Utilisateur]::new("alice")
Write-Host "Actif : $($u.EstActif())"   # True
$u.Desactiver()
Write-Host $u   # [Inactif] alice

# Utiliser l'enum
$statut = [Statut]::Actif
$statut.ToString()  # Actif
[int]$statut        # 1
```

