class Rectangle {
    [double]$Largeur
    [double]$Hauteur

    Rectangle([double]$l, [double]$h) {
        $this.Largeur = $l
        $this.Hauteur = $h
    }

    [double] Surface() { return $this.Largeur * $this.Hauteur }
    [double] Perimetre() { return 2 * ($this.Largeur + $this.Hauteur) }
}

$r = [Rectangle]::new(5, 3)
Write-Host "Surface : $($r.Surface())"
Write-Host "Périmètre : $($r.Perimetre())"

class Vehicule {
    [string]$Marque
    [int]$Vitesse

    Vehicule([string]$marque, [int]$vitesse) {
        $this.Marque   = $marque
        $this.Vitesse  = $vitesse
    }

    [string] Decrire() {
        return "$($this.Marque) à $($this.Vitesse) km/h"
    }
}

class Voiture : Vehicule {
    [int]$NbPortes

    Voiture([string]$marque, [int]$vitesse, [int]$portes) : base($marque, $vitesse) {
        $this.NbPortes = $portes
    }

    [string] Decrire() {
        return "$($this.Marque) ($($this.NbPortes) portes) à $($this.Vitesse) km/h"
    }
}

$v = [Voiture]::new("Peugeot", 130, 4)
Write-Host $v.Decrire()

class Banque {
    static [double]$TauxInteret = 2.5

    [double] CalculerInterets([double]$capital, [int]$annees) {
        $taux = [Banque]::TauxInteret / 100
        return [math]::Round($capital * ([math]::Pow(1 + $taux, $annees) - 1), 2)
    }
}

$b = [Banque]::new()
$interets = $b.CalculerInterets(10000, 5)
Write-Host "Intérêts sur 5 ans : $interets €"
